css:
.loader {
  position: relative;
  display: inline-block;
  width: 132px;
  height: 10px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(99, 102, 241, 0.15);
}
.loader::before {
  content: "";
  position: absolute;
  inset: 0 auto 0 0;
  width: 48%;
  border-radius: inherit;
  background: #6366f1;
  animation: progress 1.25s ease-in-out infinite;
}
@keyframes progress {
  0% { transform: translateX(-105%); }
  55%, 100% { transform: translateX(210%); }
}
